INSERT INTO reviews (user_id, book_id, text, created_at) VALUES
  ('a0000001-0001-0000-0000-000000000001', 'b0000001-0001-0000-0000-000000000001', 'Must-read for every developer. Clear and practical.', '2024-02-02 10:00:00+00'),
  ('a0000001-0001-0000-0000-000000000002', 'b0000001-0001-0000-0000-000000000001', 'A bit dry in places but full of good advice.', '2024-02-21 14:00:00+00'),
  ('a0000001-0001-0000-0000-000000000005', 'b0000001-0001-0000-0000-000000000001', 'Changed how I write code. Highly recommend.', '2024-03-26 13:00:00+00'),
  ('a0000001-0001-0000-0000-000000000002', 'b0000001-0001-0000-0000-000000000002', 'Classic reference. Keep it on your desk.', '2024-04-06 11:00:00+00'),
  ('a0000001-0001-0000-000000000003', 'b0000001-0001-0000-0000-000000000003', 'Best Java book I have read. Every chapter is gold.', '2024-03-02 08:00:00+00'),
  ('a0000001-0001-0000-0000-000000000001', 'b0000001-0001-0000-0000-000000000003', 'Dense but worth it. Use it as a reference.', '2024-03-20 12:00:00+00'),
  ('a0000001-0001-0000-0000-000000000004', 'b0000001-0001-0000-0000-000000000003', 'Essential for Java developers.', '2024-04-02 10:00:00+00'),
  ('a0000001-0001-0000-0000-000000000006', 'b0000001-0001-0000-0000-000000000003', 'Updated edition is great. Covers modern Java.', '2024-04-15 09:00:00+00'),
  ('a0000001-0001-0000-0000-000000000003', 'b0000001-0001-0000-0000-000000000005', 'Good intro to PostgreSQL and extensions.', '2024-03-11 16:00:00+00'),
  ('a0000001-0001-0000-0000-000000000004', 'b0000001-0001-0000-0000-000000000004', 'Solid SQL foundations. Exercises help a lot.', '2024-04-03 10:00:00+00'),
  ('a0000001-0001-0000-0000-000000000001', 'b0000001-0001-0000-0000-000000000007', 'Pragmatic advice you can use every day.', '2024-04-11 09:30:00+00'),
  ('a0000001-0001-0000-0000-000000000005', 'b0000001-0001-0000-0000-000000000007', 'Short tips, long-term impact.', '2024-04-12 10:00:00+00'),
  ('a0000001-0001-0000-0000-000000000003', 'b0000001-0001-0000-0000-000000000007', 'One of the best programming books ever.', '2024-03-25 11:00:00+00'),
  ('a0000001-0001-0000-0000-000000000002', 'b0000001-0001-0000-0000-000000000006', 'Heavy but comprehensive. Worth the time.', '2024-04-08 15:00:00+00'),
  ('a0000001-0001-0000-0000-0000-000000000006', 'b0000001-0001-0000-0000-000000000008', 'Good REST and API design concepts.', '2024-04-18 12:00:00+00');
